    // 拉取自定義列表數據
    batchChooseFormwork() {
      this.FormworkVisible = true
      this.params.page = 1
      this.getFormworkList()
    },
    onSubmitFormwork(item) {
      this.FormworkVisible = false
    }
  }
}
</script>
